```class Solution {
public:
    int maxScoreSightseeingPair(vector<int>& values) {
        int n = values.size();
        int maxScore = INT_MIN;
        for (int i = 0; i < n - 1; i++) {
            for (int j = i + 1; j < n; j++) {
                int score = values[i] + values[j] + i - j;
                maxScore = max(score, maxScore);
            }
        }
        return maxScore;
    }
};
